// NOTA: durante desarrollo, el número de Diego apunta al WhatsApp de Hugo (56992533044).
// Antes de go-live cambiar a 56940329987 (Diego Cavagnaro).
const DIEGO_WA = '56940329987';

const motivo = ($json.motivo || '').toString().slice(0, 200);
const resumen = ($json.resumen_conversacion || '').toString().slice(0, 400);

const mensaje = `Hola Diego, vengo del chat de Mirador de Villarrica.\n\n${motivo ? `Motivo: ${motivo}\n` : ''}${resumen ? `Contexto: ${resumen}` : ''}`.trim();
const url = `https://wa.me/${DIEGO_WA}?text=${encodeURIComponent(mensaje)}`;

return [{ json: {
  type: 'whatsapp_link',
  url,
  label: 'Hablar con Diego por WhatsApp',
  preview_text: mensaje,
  tool_output_text: 'Te dejo el contacto directo de Diego. Al tocar el botón se abre WhatsApp con un mensaje precargado con el contexto de esta conversación.',
} }];
